const { execSync } = require('child_process');
const output = execSync('docker compose --profile prepare -f /workspace/docker-compose.yml up --exit-code-from prepare_dataset', {timeout: 600000}).toString();
return [{ json: { stage: "prepare", output: output } }];

const { execSync } = require('child_process');
const output = execSync('EPOCHS=1 docker compose --profile train -f /workspace/docker-compose.yml up --exit-code-from train', {timeout: 600000}).toString();
const runIdMatch = output.match(/"run_id":\s*"([^"]+)"/);
const runId = runIdMatch ? runIdMatch[1] : 'unknown';
return [{ json: { stage: "train", run_id: runId, output: output } }];

const input = $input.all()[0].json;
const runId = input.run_id;
const fs = require('fs');
const metadata = JSON.parse(fs.readFileSync(`/workspace/artifacts/${runId}/metadata.json`, 'utf8'));
const approved = metadata.metric_value >= metadata.threshold;
return [{ json: { stage: "validate", run_id: runId, approved: approved, metric: metadata.metric_value, threshold: metadata.threshold } }];

const input = $input.all()[0].json;
if (!input.approved) throw new Error("Modelo rejeitado - deploy bloqueado");
const runId = input.run_id;
return [{ json: { stage: "publish", run_id: runId, status: "published" } }];

const { execSync } = require('child_process');
const input = $input.all()[0].json;
const runId = input.run_id;
const output = execSync(`DEFAULT_RUN_ID=${runId} docker compose --profile api -f /workspace/docker-compose.yml up -d`, {timeout: 300000}).toString();
return [{ json: { stage: "deploy", run_id: runId, output: output } }];
